import React, { useState, useEffect } from 'react';
import axios from 'axios';

function HomePage() {
  const [videos, setVideos] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => setVideos(response.data))
      .catch(error => console.error(error));
  }, []);

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 24 }}>
        {videos.map(video => (
          <div key={video.id} style={{ cursor: 'pointer' }} onClick={() => window.location.href = `/video/${video.id}`}>
            <video src={`http://localhost:8000${video.video_file}`} style={{ width: '100%', borderRadius: 12 }} />
            <h3 style={{ color: 'white', marginTop: 10 }}>{video.title}</h3>
          </div>
        ))}
      </div>
    </div>
  );
}

export default HomePage;
